module down_counter_4bit(
    input clk,          // Chip clock signal.
    input rst_n,        // Active-low reset signal.
    input en,           // Enable signal to allow counting.
    input load,         // Load signal to load the counter value.
    input [3:0] load_val, // 4-bit input value to be loaded into the counter.

    output [3:0] count  // 4-bit count value.
);

reg [3:0] cnt_reg;

//------------------------------------------------
// Counter logic
always @(posedge clk or negedge rst_n)
    if (!rst_n) cnt_reg <= 4'd0;  // Reset counter
    else if (load) cnt_reg <= load_val; // Load counter
    else if (en) begin
        if (cnt_reg == 4'd0) cnt_reg <= 4'd15; // Wrap around
        else cnt_reg <= cnt_reg - 1'b1;        // Decrement counter
    end

assign count = cnt_reg;

endmodule
